import React from "react";

const Card = ({ title, description, imageUrl, onClick }) => {
  return (
    <button
      onClick={onClick}
      className="focus:outline-none transform hover:scale-105 transition duration-300"
    >
      <div className="max-w-xs rounded-xl overflow-hidden shadow-2xl bg-gradient-to-r from-blue-600 via-blue-500 to-blue-400 text-white">
        <div className="py-8 px-8">
          <div className="font-bold text-xl mb-2">{title || "Unknown Gem"}</div>
          <p className="text-white/90 text-base">{description || "Unknown Shape"}</p>
        </div>
      </div>
    </button>
  );
};

export default Card;
